const items = $input.all();
const results = [];

for (const item of items) {
  const da = item.json;
  results.push({
    json: {
      id: da.DefectActId,
      act_number: da.ActNumber || null,
      defect_date: da.DefectActDate || null,
      object_id: da.ObjectId || null,
      problem: da.Problem || null,
      place: da.Place || null,
      description: da.Description || null,
      solution: da.Solution || null,
      status: da.Status || 'Unknown',
      system_id: da.SystemosId || null,
      system_group_id: da.SystGroupId || null,
      inspection_date: da.InspectionDate || null,
      clerk_id: da.ClerkId || null,
      owner_id: da.OwningSystemUserId || null,
      labbis_id: da.DefectActId
    }
  });
}

return results;

const items = $input.all();
let created = 0;
let skipped = 0;
let errors = 0;

for (const item of items) {
  const status = item.json?.statusCode;
  if (status === 200 || status === 204 || item.json?.data?.id) {
    created++;
  } else if (status === 400 && JSON.stringify(item.json).includes('unique')) {
    skipped++;
  } else {
    errors++;
  }
}

return [{
  json: {
    total_processed: items.length,
    created,
    skipped,
    errors,
    timestamp: new Date().toISOString()
  }
}];
